Here's a Node.js example of command injection using `child_process.exec`. This script is intentionally vulnerable for educational use in your security training lab.

---

## Vulnerable Node.js Script

```javascript
// vulnerable-ping.js — For training purposes only. DO NOT USE IN PRODUCTION.

const { exec } = require('child_process');
const readline = require('readline');

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout
});

console.log('='.repeat(60));
console.log('   NODE.JS COMMAND INJECTION LAB  (VULNERABLE SCRIPT)');
console.log('='.repeat(60));
console.log('We run: ping -c 4 <YOUR_INPUT>');
console.log('Commands are run via child_process.exec with shell interpretation.');
console.log('Special characters (;, &&, |, etc.) can inject extra commands.\n');

rl.question('Enter a target (e.g., localhost, 127.0.0.1): ', (userInput) => {
  // VULNERABLE: String concatenation + exec() uses a shell
  const command = `ping -c 4 ${userInput}`;

  console.log(`\n[*] Constructed shell command: ${command}\n`);
  console.log('[*] Executing...\n');

  // exec() spawns a shell (/bin/sh on Unix, cmd.exe on Windows)
  exec(command, (error, stdout, stderr) => {
    console.log('='.repeat(60));
    console.log('STDOUT:');
    console.log(stdout);

    if (stderr) {
      console.log('STDERR:');
      console.log(stderr);
    }

    if (error) {
      console.log(`Execution error: ${error.message}`);
    }

    console.log('\n' + '='.repeat(60));
    console.log('HOW INJECTION WORKED:');
    console.log('- exec() passes the whole string to the system shell.');
    console.log('- The shell interprets ;, &&, |, & as command separators.');
    console.log('- Your input was inserted directly into the command string.');
    console.log('- Any extra commands you chained were executed too.');
