#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_INPUT 1024

int main() {
    char *query_string;
    char host[MAX_INPUT];
    char command[MAX_INPUT + 64];   // room for "ping -c 4 " prefix

